content:
:root {
  --neon-pink: #ff00ff;
  --neon-cyan: #00ffff;
  --dark-bg: #050505;
  --card-bg: rgba(10, 10, 10, 0.9);
  --font-main: 'Courier New', Courier, monospace;
  --glitch-speed: 0.3s;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background-color: var(--dark-bg);
  color: #fff;
  font-family: var(--font-main);
  height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  position: relative;
}

/* Background Scanlines Effect */
body::before {
  content: " ";
  display: block;
  position: absolute;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.06), rgba(0, 255, 0, 0.02), rgba(0, 0, 255, 0.06));
  z-index: 2;
  background-size: 100% 2px, 3px 100%;
  pointer-events: none;
}

.container {
  position: relative;
  z-index: 10;
  width: 100%;
  max-width: 400px;
  padding: 20px;
}

.login-card {
  background: var(--card-bg);
  border: 2px solid var(--neon-cyan);
  padding: 40px;
  box-shadow: 0 0 15px var(--neon-cyan), inset 0 0 10px rgba(0, 255, 255, 0.2);
  position: relative;
  clip-path: polygon(0% 0%, 100% 0%, 100% 90%, 90% 100%, 0% 100%);
}

.login-card::after {
  content: "ACCESS TERMINAL";
  position: absolute;
  top: -12px;
  left: 20px;
  background: var(--dark-bg);
  padding: 0 10px;
  color: var(--neon-cyan);
  font-size: 0.8rem;
  letter-spacing: 2px;
}

.title {
  text-align: center;
  font-size: 2rem;
  margin-bottom: 30px;
  color: var(--neon-pink);
  text-shadow: 2px 2px var(--neon-cyan);
  text-transform: uppercase;
  letter-spacing: 4px;
}

/* Glitch Effect for Title */
.glitch {
  position: relative;
}

.glitch::before,
.glitch::after {
  content: attr(data-text);
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--dark-bg);
}

.glitch::before {
  left: 2px;
  text-shadow: -2px 0 var(--neon-cyan);
  clip: rect(44px, 450px, 56px, 0);
  animation: glitch-anim 5s infinite linear alternate-reverse;
}

.glitch::after {
  left: -2px;
  text-shadow: -2px 0 var(--neon-pink);
  clip: rect(44px, 450px, 56px, 0);
  animation: glitch-anim2 5s infinite linear alternate-reverse;
}

.form-group {
  margin-bottom: 20px;
}

label {
  display: block;
  color: var(--neon-cyan);
  margin-bottom: 8px;
  font-size: 0.9rem;
  text-transform: uppercase;
}

input[type="text"],
input[type="password"] {
  width: 100%;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--neon-pink);
  padding: 12px;
  color: #fff;
  font-family: var(--font-main);
  outline: none;
  transition: all 0.3s ease;
}

input:focus {
  box-shadow: 0 0 10px var(--neon-pink);
  background: rgba(255, 0, 255, 0.1);
}

.login-btn {
  width: 100%;
  padding: 15px;
  background: transparent;
  border: 2px solid var(--neon-cyan);
  color: var(--neon-cyan);
  font-family: var(--font-main);
  font-weight: bold;
  text-transform: uppercase;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
  overflow: hidden;
}

.login-btn:hover {
  background: var(--neon-cyan);
  color: var(--dark-bg);
  box-shadow: 0 0 20px var(--neon-cyan);
}

.error-msg {
  color: #ff0000;
  font-size: 0.8rem;
  margin-top: 15px;
  text-align: center;
  border: 1px dashed #ff0000;
  padding: 5px;
  animation: blink 1s step-end infinite;
}

.success-msg {
  color: var(--neon-cyan);
  font-size: 0.8rem;
  margin-top: 15px;
  text-align: center;
  border: 1px dashed var(--neon-cyan);
  padding: 5px;
}

/* Animations */
@keyframes glitch-anim {
  0% { clip: rect(31px, 9999px, 94px, 0); }
  20% { clip: rect(62px, 9999px, 42px, 0); }
  40% { clip: rect(16px, 9999px, 78px, 0); }
  60% { clip: rect(55px, 9999px, 12px, 0); }
  80% { clip: rect(92px, 9999px, 50px, 0); }
  100% { clip: rect(10px, 9999px, 85px, 0); }
}

@keyframes glitch-anim2 {
  0% { clip: rect(65px, 9999px, 100px, 0); }
  20% { clip: rect(10px, 9999px, 50px, 0); }
  40% { clip: rect(80px, 9999px, 20px, 0); }
  60% { clip: rect(30px, 9999px, 70px, 0); }
  80% { clip: rect(50px, 9999px, 90px, 0); }
  100% { clip: rect(20px, 9999px, 40px, 0); }
}

@keyframes blink {
  from, to { opacity: 1; }
  50% { opacity: 0; }
}
